import React, { useState, useEffect } from 'react';
import './WeatherMap.css';

const WeatherMap = ({ weather }) => {
  const [coords, setCoords] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!weather) return;
    setLoading(true);
    // Use OpenWeatherMap geocoding to get lat/lon from city name
    const API_KEY = 'a585df6a154c5d9f7768ea48d6d84d1f';
    fetch(`https://api.openweathermap.org/geo/1.0/direct?q=${encodeURIComponent(weather.name)}&limit=1&appid=${API_KEY}`)
      .then(r => r.json())
      .then(data => {
        if (data && data[0]) {
          setCoords({ lat: data[0].lat, lon: data[0].lon });
        }
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [weather?.name]);

  if (!weather) return (
    <div className="map-empty">
      <span className="map-empty-icon">🗺️</span>
      <p>Search a city to see its location</p>
    </div>
  );

  if (loading) return (
    <div className="map-empty">
      <div className="map-spinner"/>
      <p>Loading map…</p>
    </div>
  );

  if (!coords) return (
    <div className="map-empty">
      <span className="map-empty-icon">📍</span>
      <p>{weather.name}, {weather.country}</p>
    </div>
  );

  const mapUrl = `https://www.openstreetmap.org/export/embed.html?bbox=${coords.lon-0.15},${coords.lat-0.1},${coords.lon+0.15},${coords.lat+0.1}&layer=mapnik&marker=${coords.lat},${coords.lon}`;

  return (
    <div className="map-wrap">
      <div className="map-coords-badge">
        📍 {coords.lat.toFixed(3)}°, {coords.lon.toFixed(3)}°
      </div>
      <iframe
        title="City Map"
        src={mapUrl}
        className="map-iframe"
        loading="lazy"
        referrerPolicy="no-referrer"
      />
      <a
        className="map-link"
        href={`https://www.openstreetmap.org/?mlat=${coords.lat}&mlon=${coords.lon}#map=12/${coords.lat}/${coords.lon}`}
        target="_blank"
        rel="noreferrer"
      >
        Open full map ↗
      </a>
    </div>
  );
};

export default WeatherMap;
